import React, { createContext, useEffect, useState } from 'react';
import supabase from '../utils/supabaseClient';

export const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
	const [userAccount, setUserAccount] = useState(null)
	const [loggedIn, setLoggedIn] = useState(false);
	const [userName, setUserName] = useState(null);
	const [votedToday, setVotedToday] = useState(false);
	const [locationDate, setLocationDate] = useState('')

	const signUp = async (email, password, name) => {
		if (email && password && name) {
			const { data, error } = await supabase.auth.signUp({
				email,
				password,
				options: {
				data: { name },
				emailRedirectTo: window.location.origin,
				},
			});
			
			if (error) throw error;
				return data;
			} else {
				throw new Error('Please provide email, password, and name');
			}
	};

	const signIn = async (email, password) => {
        if (!email || !password) {
            alert('Please enter both email and password');
            return null;
        }

        try {
            const { data, error } = await supabase.auth.signInWithPassword({
                email,
                password,
            });

            if (error) throw error;

            setLoggedIn(true);
            setUserName(data.user.user_metadata?.name || '');
			setUserAccount(data.user);

            // Optional: Store session in localStorage (Supabase already uses localStorage under the hood)
            // Optional: Load weather data, stats, etc. if needed here
			return data;

        } catch (error) {
            console.error('❌ Login error:', error);
            alert(error.message);
        }
    };

	const signOut = async () => {
		try {
			const { error } = await supabase.auth.signOut({ scope: 'local' });
				if (error) {
				return;
			}
			setUserName(null);
			setLoggedIn(false);
			setVotedToday(false);
			setUserAccount(null);
		} catch (err) {
			console.error('Exception during sign out:', err);
		}
	};

	const resetPassword = async (email) => {
		const { error } = await supabase.auth.resetPasswordForEmail(email, {
			redirectTo: 'https://top10weather.com/#/reset-password',
		});
		return error;
	};

    const submitVote = async (vote, weatherData) => {
		if (!weatherData) {
			return;
		}

		try {
			const voteData = {
				user_id: userAccount.id,
				user_email: userAccount.email,
				is_top10: vote,
				temperature: weatherData.temperature,
				conditions: weatherData.conditions,
				humidity: weatherData.humidity,
				wind_speed: weatherData.windSpeed,
				uv_index: weatherData.uvIndex,
				feels_like: weatherData.feelsLike,
				pressure: weatherData.pressure,
				visibility: weatherData.visibility,
				location: weatherData.location,
				user_agent: navigator.userAgent,
				is_manual_entry: weatherData.isManualEntry || false,
				date: locationDate
			};

			const { error } = await supabase
				.from('weather_votes')
				.insert([voteData]);

			if (error) {
				throw new Error('❌ Supabase error details:', error.message);
			}

			setVotedToday(true);

		} catch (error) {
			console.error('❌ Vote submission error:', error);
		}
    }

	const checkIfVotedToday = async (user) => {
		if (!user) return;

		try {
			const today = new Date().toISOString().split('T')[0]; // 'YYYY-MM-DD'
			const { data, error } = await supabase
			.from('weather_votes')
			.select('id')
			.eq('user_id', user.id)
			.eq('date', today);
			
			if (error) throw error;
			
			setVotedToday(data.length > 0);
		} catch (error) {
			console.error('❌ Error checking vote status:', error);
		}
	};

	useEffect(() => {
		const getSession = async () => {
			try {
				const { data: { session }, error } = await supabase.auth.getSession();
		
				if (error) {
					console.error('Error fetching session:', error);
				}
				
				if (session?.user) {
					setUserName(session.user.user_metadata?.name || session.user.email);
					setLoggedIn(true);
					setUserAccount(session.user);
					await checkIfVotedToday(session.user);
				} else {
					setUserName(null);
					setLoggedIn(false);
					setUserAccount(null);
					setVotedToday(false);
				}
			} catch (err) {
				console.error('Exception in getSession:', err);
			}
		};
		
		getSession();
		
		const { data: listener } = supabase.auth.onAuthStateChange( (_event, session) => {
			if (session?.user) {
				setUserName(session.user.user_metadata?.name || session.user.email);
				setLoggedIn(true);
				setUserAccount(session.user)
				checkIfVotedToday(session.user);
			} else {
				setUserName(null);
				setLoggedIn(false);
				setVotedToday(false);
				setUserAccount(null)
			}
	});
	
	return () => {
		listener.subscription.unsubscribe();
	};
	}, []);

	return (
		<AuthContext.Provider
			value={{
				loggedIn,
				userName,
				votedToday,
				locationDate,
				setUserName,
				setVotedToday,
				signUp,
				signIn,
				signOut,
				resetPassword,
				submitVote,
				setLocationDate
			}}
		>
			{children}
		</AuthContext.Provider>
	);
};
